.story-dashboard {
    width: 100%;
    max-width: 700px;
    box-sizing: border-box;
    margin: 0 auto;
    padding: 20px 16px;
}

.story-dashboard-loading {
    display: flex;
    justify-content: center;
    padding: 60px 0;
}

.story-dashboard-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 24px;
}

.story-dashboard-title {
    font-size: 1.4rem;
    font-weight: 600;
    color: var(--text-primary);
    margin: 0;
}

.story-dashboard-new-btn {
    padding: 8px 18px;
    border-radius: 8px;
    border: none;
    background: var(--accent-dark);
    color: var(--bg-primary);
    font-size: 0.85rem;
    font-weight: 500;
    cursor: pointer;
    transition: opacity 0.15s ease;
}

.story-dashboard-new-btn:hover {
    opacity: 0.85;
}

.story-dashboard-empty {
    text-align: center;
    padding: 60px 20px;
    color: var(--text-secondary);
}

.story-dashboard-empty p {
    margin-bottom: 16px;
    font-size: 0.95rem;
}

.story-dashboard-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.story-dashboard-card {
    display: flex;
    align-items: center;
    gap: 14px;
    padding: 14px;
    background: var(--bg-glass);
    backdrop-filter: blur(10px);
    border: 1px solid var(--bg-glass-border);
    border-radius: 12px;
    cursor: pointer;
    transition: background-color 0.12s ease, box-shadow 0.12s ease;
}

.story-dashboard-card:hover {
    background: var(--bg-hover);
    box-shadow: var(--shadow-card);
}

.story-dashboard-card-cover {
    width: 60px;
    height: 80px;
    border-radius: 8px;
    overflow: hidden;
    flex-shrink: 0;
    background: var(--bg-secondary);
}

.story-dashboard-card-cover img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.story-dashboard-card-cover-placeholder {
    width: 100%;
    height: 100%;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--bg-secondary);
}

.story-dashboard-card-info {
    flex: 1;
    min-width: 0;
}

.story-dashboard-card-title {
    font-size: 0.95rem;
    font-weight: 600;
    color: var(--text-primary);
    margin: 0 0 6px 0;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.story-dashboard-card-meta {
    display: flex;
