.story-library {
    width: 100%;
    max-width: 700px;
    box-sizing: border-box;
    margin: 0 auto;
    padding: 20px 16px;
}

.story-library-loading {
    display: flex;
    justify-content: center;
    padding: 60px 0;
}

.story-library-header {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 24px;
}

.story-library-back {
    width: 34px;
    height: 34px;
    border: none;
    background: var(--bg-secondary);
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    flex-shrink: 0;
    transition: background-color 0.12s ease;
}

.story-library-back:hover {
    background: var(--bg-hover);
}

.story-library-title {
    font-size: 1.4rem;
    font-weight: 600;
    color: var(--text-primary);
    margin: 0;
}

.story-library-empty {
    text-align: center;
    padding: 60px 20px;
    color: var(--text-secondary);
}

.story-library-empty p {
    margin-bottom: 16px;
    font-size: 0.95rem;
}

.story-library-browse-btn {
    padding: 8px 18px;
    border-radius: 8px;
    border: none;
    background: var(--accent-dark);
    color: var(--bg-primary);
    font-size: 0.85rem;
    font-weight: 500;
    cursor: pointer;
    transition: opacity 0.15s ease;
