.story-dashboard {
    width: 100%;
    max-width: 700px;
    box-sizing: border-box;
    margin: 0 auto;
    padding: 20px 16px;
}

.story-dashboard-loading {
    display: flex;
    justify-content: center;
    padding: 60px 0;
}

.story-dashboard-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 24px;
}

.story-dashboard-title {
    font-size: 1.4rem;
    font-weight: 600;
    color: var(--text-primary);
    margin: 0;
}

.story-dashboard-new-btn {
    padding: 8px 18px;
    border-radius: 8px;
    border: none;
    background: var(--accent-dark);
    color: var(--bg-primary);
    font-size: 0.85rem;
    font-weight: 500;
    cursor: pointer;
    transition: opacity 0.15s ease;
}

.story-dashboard-new-btn:hover {
    opacity: 0.85;
}

.story-dashboard-empty {
    text-align: center;
    padding: 60px 20px;
    color: var(--text-secondary);
}

.story-dashboard-empty p {
    margin-bottom: 16px;
    font-size: 0.95rem;
}

.story-dashboard-list {
